import java.util.Scanner;public class MiniLoja {    public static void main(String[] args) {        System.out.println("Qual dos produtos você deseja? ");        System.out.println("[ 1 ] Arroz");        System.out.println("[ 2 ] Feijao");        System.out.println("[ 3 ] Macarrão (Espaguete)");        System.out.println("[ 4 ] Carne");        System.out.println("[ 5 ] Refrigerante");        Scanner input = new Scanner(System.in);        int produtos = input.nextInt();        System.out.println("Quantos reais você tem? R$");        Scanner inputSaldoDisponivel = new Scanner(System.in);        double saldoDisponivel = inputSaldoDisponivel.nextFloat();        System.out.println("Você tem " + saldoDisponivel + "R$");        if (saldoDisponivel <= 0) {            System.out.println("Você não pode fazer compras, pois não tem R$ suficiente!");        } else {            switch (produtos) {                case 1:                    saldoDisponivel -= 50;                    System.out.println("Você comprou arroz, lhe resta " + saldoDisponivel);                    break;                case 2:                    saldoDisponivel -= 30;                    System.out.println("Você comprou feijão, sobrou " + saldoDisponivel);                    break;                case 3:                    saldoDisponivel -= 25;                    System.out.println("Você comprou espaguete e ainda tem " + saldoDisponivel + "R$");                    break;                case 4:                    saldoDisponivel -= 70;                    System.out.println("Você comprou carne e ta caro pakacete faiz o L, sobrou " + saldoDisponivel + "R$");                    break;                case 5:                    saldoDisponivel -= 15;                    System.out.println("Você comprou refrigerante e sobrou " + saldoDisponivel + "R$");                    break;            }        }    }}